import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom'; // Use Navigate for redirection
import './App.css';
import LoginPage from './Components/Login';
import SignupPage from './Components/Signup';
import SideNav from './Components/SideNav'; // Import the SideNav component
import ChatBox from './Components/ChatBox';
import HomePage from './Components/HomePage'; // Import the HomePage component

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false); // Manage login state

  // Handle login success (simulate login in this case)
  const login = () => {
    setIsAuthenticated(true);
  };

  // Handle logout (simulate logout)
  const logout = () => {
    setIsAuthenticated(false);
  };

  return (
    <Router>
      <div className="App">
        <h1>J-Test</h1>

        {/* Render SideNav only if authenticated */}
        {isAuthenticated && <SideNav logout={logout} />} {/* Pass logout to SideNav */}

        <Routes>
          {/* Login Route */}
          <Route path="/Login" element={<LoginPage login={login} />} />

          {/* Signup Route */}
          <Route path="/Signup" element={<SignupPage />} />

          {/* HomePage Route */}
          <Route path="/HomePage" element={<HomePage />} />

          {/* ChatBox Route */}
          <Route path="/ChatBox" element={<ChatBox />} />

          {/* Default route */}
          <Route path="/" element={<Navigate to="/Login" />} /> {/* Default redirect to login */}
        </Routes>
      </div>
    </Router>
  );
}

export default App;
